CREATE TYPE "AcademyEmailCampaignStatus" AS ENUM ('DRAFT','SCHEDULED','SENDING','SENT','CANCELLED');
CREATE TYPE "AcademyEmailDeliveryStatus" AS ENUM ('QUEUED','PROCESSING','SENT','FAILED');
ALTER TABLE "Course" ADD COLUMN "learningOutcomes" TEXT[] NOT NULL DEFAULT ARRAY[]::TEXT[], ADD COLUMN "targetAudience" TEXT, ADD COLUMN "notForAudience" TEXT, ADD COLUMN "prerequisites" TEXT[] NOT NULL DEFAULT ARRAY[]::TEXT[], ADD COLUMN "trailerVideoId" TEXT, ADD COLUMN "samplePdfUrl" TEXT, ADD COLUMN "salesFaqs" JSONB NOT NULL DEFAULT '[]';
ALTER TABLE "AcademyMarketingLead" ADD COLUMN "tags" TEXT[] NOT NULL DEFAULT ARRAY[]::TEXT[], ADD COLUMN "utmSource" TEXT, ADD COLUMN "utmMedium" TEXT, ADD COLUMN "utmCampaign" TEXT, ADD COLUMN "convertedAt" TIMESTAMP(3);
CREATE TABLE "AcademyOrderItem" ("id" TEXT NOT NULL,"orderId" TEXT NOT NULL,"courseId" TEXT,"bundleId" TEXT,"title" TEXT NOT NULL,"unitPrice" DECIMAL(10,2) NOT NULL,"courseIds" TEXT[] NOT NULL DEFAULT ARRAY[]::TEXT[],"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "AcademyOrderItem_pkey" PRIMARY KEY ("id"));
CREATE INDEX "AcademyOrderItem_orderId_idx" ON "AcademyOrderItem"("orderId");
ALTER TABLE "AcademyOrderItem" ADD CONSTRAINT "AcademyOrderItem_orderId_fkey" FOREIGN KEY ("orderId") REFERENCES "AcademyOrder"("id") ON DELETE CASCADE ON UPDATE CASCADE;
CREATE TABLE "AcademyEmailCampaign" ("id" TEXT NOT NULL,"name" TEXT NOT NULL,"subject" TEXT NOT NULL,"content" TEXT NOT NULL,"audience" TEXT NOT NULL,"courseId" TEXT,"scheduledAt" TIMESTAMP(3),"status" "AcademyEmailCampaignStatus" NOT NULL DEFAULT 'DRAFT',"sentAt" TIMESTAMP(3),"recipients" INTEGER NOT NULL DEFAULT 0,"sentCount" INTEGER NOT NULL DEFAULT 0,"failedCount" INTEGER NOT NULL DEFAULT 0,"openedCount" INTEGER NOT NULL DEFAULT 0,"clickedCount" INTEGER NOT NULL DEFAULT 0,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "AcademyEmailCampaign_pkey" PRIMARY KEY ("id"));
CREATE INDEX "AcademyEmailCampaign_status_scheduledAt_idx" ON "AcademyEmailCampaign"("status","scheduledAt");
CREATE TABLE "AcademyEmailDelivery" ("id" TEXT NOT NULL,"campaignId" TEXT NOT NULL,"email" TEXT NOT NULL,"status" "AcademyEmailDeliveryStatus" NOT NULL DEFAULT 'QUEUED',"attempts" INTEGER NOT NULL DEFAULT 0,"nextAttemptAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"sentAt" TIMESTAMP(3),"openedAt" TIMESTAMP(3),"clickedAt" TIMESTAMP(3),"lastError" TEXT,"token" TEXT NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "AcademyEmailDelivery_pkey" PRIMARY KEY ("id"));
CREATE UNIQUE INDEX "AcademyEmailDelivery_token_key" ON "AcademyEmailDelivery"("token");CREATE UNIQUE INDEX "AcademyEmailDelivery_campaignId_email_key" ON "AcademyEmailDelivery"("campaignId","email");CREATE INDEX "AcademyEmailDelivery_status_nextAttemptAt_idx" ON "AcademyEmailDelivery"("status","nextAttemptAt");ALTER TABLE "AcademyEmailDelivery" ADD CONSTRAINT "AcademyEmailDelivery_campaignId_fkey" FOREIGN KEY ("campaignId") REFERENCES "AcademyEmailCampaign"("id") ON DELETE CASCADE ON UPDATE CASCADE;
CREATE TABLE "AcademyMedia" ("id" TEXT NOT NULL,"url" TEXT NOT NULL,"mobileUrl" TEXT,"avifUrl" TEXT,"mobileAvifUrl" TEXT,"thumbnailUrl" TEXT,"alt" TEXT NOT NULL,"kind" TEXT NOT NULL,"width" INTEGER,"height" INTEGER,"sizeBytes" INTEGER,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "AcademyMedia_pkey" PRIMARY KEY ("id"));
CREATE TABLE "AcademyAutomationLog" ("id" TEXT NOT NULL,"userId" TEXT NOT NULL,"courseId" TEXT,"orderId" TEXT,"type" TEXT NOT NULL,"sentAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"details" JSONB,CONSTRAINT "AcademyAutomationLog_pkey" PRIMARY KEY ("id"));CREATE UNIQUE INDEX "AcademyAutomationLog_userId_courseId_orderId_type_key" ON "AcademyAutomationLog"("userId","courseId","orderId","type");CREATE INDEX "AcademyAutomationLog_type_sentAt_idx" ON "AcademyAutomationLog"("type","sentAt");
CREATE TABLE "AcademyOperationalEvent" ("id" TEXT NOT NULL,"severity" TEXT NOT NULL,"source" TEXT NOT NULL,"message" TEXT NOT NULL,"details" JSONB,"resolvedAt" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "AcademyOperationalEvent_pkey" PRIMARY KEY ("id"));CREATE INDEX "AcademyOperationalEvent_severity_resolvedAt_createdAt_idx" ON "AcademyOperationalEvent"("severity","resolvedAt","createdAt");
